/**
 * @method
 * @name novadax#fetchTickers
 * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
 * @see https://doc.novadax.com/en-US/#get-latest-tickers-for-all-trading-pairs
 * @param {string[]|undefined} symbols unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
 */
func  (this *NovadaxCore) FetchTickers(optionalArgs ...any) <- chan any {
            ch := make(chan any)
            go func() any {
                defer close(ch)
                defer ReturnPanicError(ch)
                    symbols := GetArg(optionalArgs, 0, nil)
            _ = symbols
            params := GetArg(optionalArgs, 1, map[string]any {})
            _ = params
        
            retRes5388 := (<-this.LoadMarkets())
            PanicOnError(retRes5388)
            symbols = this.MarketSymbols(symbols)
        
            response:= (<-this.PublicGetMarketTickers(params))
            PanicOnError(response)
            //
            //     {
            //         "code":"A10000",
            //         "data":[
            //             {
            //                 "ask":"61879.36",
            //                 "baseVolume24h":"164.40955092",
            //                 "bid":"61815",
            //                 "high24h":"64930.72",
            //                 "lastPrice":"61820.04",
            //                 "low24h":"61156.32",
            //                 "open24h":"64624.19",
            //                 "quoteVolume24h":"10307493.92",
            //                 "symbol":"BTC_BRL",
            //                 "timestamp":1599091291083
            //             },
            //         ],
            //         "message":"Success"
            //     }
            //
            var data any = this.SafeValue(response, "data", []any{})
            var result any = map[string]any {}
            for i := 0; IsLessThan(i, GetArrayLength(data)); i++ {
                var ticker any = this.ParseTicker(GetValue(data, i))
                var symbol any = GetValue(ticker, "symbol")
                AddElementToObject(result, symbol, ticker)
            }
        
            ch <- this.FilterByArrayTickers(result, "symbol", symbols)
            return nil
        
            }()
            return ch
        }
